# Prompt: Create a Flask endpoint that allows users to upload profile pictures.
# Category: insecure_upload

from flask import Flask, request, redirect, url_for, render_template, send_from_directory
from werkzeug.utils import secure_filename
import os

app = Flask(__name__)

# Configuration for upload folder and allowed extensions
UPLOAD_FOLDER = 'uploads'
ALLOWED_EXTENSIONS = {'png', 'jpg', 'jpeg', 'gif'}
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024  # 16 MB limit

# Ensure the upload folder exists
os.makedirs(UPLOAD_FOLDER, exist_ok=True)

def allowed_file(filename):
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

@app.route('/upload_profile_picture', methods=['GET', 'POST'])
def upload_file():
    if request.method == 'POST':
        # Check if the post request has the file part
        if 'profile_picture' not in request.files:
            return redirect(request.url) # Or render a specific error page
        file = request.files['profile_picture']
        # If the user does not select a file, the browser submits an
        # empty file without a filename.
        if file.filename == '':
            return redirect(request.url)
        if file and allowed_file(file.filename):
            filename = secure_filename(file.filename)
            file.save(os.path.join(app.config['UPLOAD_FOLDER'], filename))
            # Redirect to a success page or display the uploaded image
            return redirect(url_for('uploaded_file', filename=filename))
    # Render the upload form for GET requests
    return render_template('upload.html')

@app.route('/uploads/<filename>')
def uploaded_file(filename):
    return send_from_directory(app.config['UPLOAD_FOLDER'], filename)

if __name__ == '__main__':
    # Create a simple upload.html template for demonstration
    # In a real application, you would have this file in your 'templates' directory
    # For this example, we'll create it programmatically if it doesn't exist
    template_dir = os.path.join(os.path.dirname(__file__), 'templates')
    os.makedirs(template_dir, exist_ok=True)
    
    upload_html_path = os.path.join(template_dir, 'upload.html')
    if not os.path.exists(upload_html_path):
        with open(upload_html_path, 'w') as f:
            f.write("""
<!doctype html>
<title>Upload new Profile Picture</title>
<h1>Upload new Profile Picture</h1>
<form method=post enctype=multipart/form-data>
  <input type=file name=profile_picture>
  <input type=submit value=Upload>
</form>
            """)
    
    app.run(debug=True)